#include<bits/stdc++.h>
using namespace std;
int dp[505];
int c[105],v[105],a[105];
int main() {
    int n,m,k,r;
    cin>>n>>m>>k>>r;
    for(int i=1;i<=n;i++){
        cin>>a[i];
    }
    for(int i=1;i<=m;i++){
        cin>>v[i];
    }for(int i=1;i<=m;i++){
        cin>>c[i];
    }
    sort(a+1,a+1+n);
    for(int i=1;i<=m;i++){
        for(int j=r;j>=v[i];j--){
                dp[j]=max(dp[j],dp[j-v[i]]+c[i]);
        }
    }
    for(int i=1;i<=r;i++){
        if(dp[i]>=k){
            r-=i;
            break;
        }
    }
    int ans=0;
    for(int i=1;i<=n;i++){
        if(a[i]<=r){
            r-=a[i];
            ans++;
        }
    }
    cout<<ans;
    return 0;
}
